example.code:
from dataclasses import dataclass, field from datetime import datetime from typing import Optional
@dataclass class ExperimentEvent: experiment_id: str variant: str user_id: str event_type: str # "exposure" | "conversion" metric_name: Optional[str] = None metric_value: Optional[float] = None timestamp: datetime = field(default_factory=datetime.utcnow) properties: dict = field(default_factory=dict)
class ExperimentTracker: def __init__(self, analytics_client, assigner): self.analytics = analytics_client self.assigner = assigner self._exposures: set[tuple[str, str]] = set() # (exp_id, user_id)
def track_exposure(self, experiment_id: str, user_id: str): key = (experiment_id, user_id) if key in self._exposures: return # deduplicate within session variant = self.assigner.get_variant(experiment_id, user_id) if not variant: return self._exposures.add(key) self.analytics.track("experiment_exposure", ExperimentEvent( experiment_id=experiment_id, variant=variant, user_id=user_id, event_type="exposure" ).__dict__)
def track_conversion(self, experiment_id: str, user_id: str, metric_name: str, value: float = 1.0): variant = self.assigner.get_variant(experiment_id, user_id) if not variant: return self.analytics.track("experiment_conversion", ExperimentEvent( experiment_id=experiment_id, variant=variant, user_id=user_id, event_type="conversion", metric_name=metric_name, metric_value=value ).__dict__)
